@import "tailwindcss";
@import "tw-animate-css";

@custom-variant dark (&:is(.dark *));

:root {
	--dracula-bg: #000000;
	--dracula-fg: #f8f8f2;
	--dracula-current: #44475a;
	--dracula-comment: #6272a4;
	--dracula-cyan: #8be9fd;
	--dracula-green: #50fa7b;
	--dracula-orange: #ffb86c;
	--dracula-pink: #ff79c6;
	--dracula-purple: #bd93f9;
	--dracula-red: #ff5555;
	--dracula-yellow: #f1fa8c;

	--radius: 0.625rem;
	--background: var(--dracula-bg);
	--foreground: var(--dracula-fg);
	--card: #000000;
	--card-foreground: var(--dracula-fg);
	--popover: var(--dracula-current);
	--popover-foreground: var(--dracula-fg);
	--primary: var(--dracula-purple);
	--primary-foreground: var(--dracula-bg);
	--secondary: var(--dracula-comment);
	--secondary-foreground: var(--dracula-fg);
	--muted: var(--dracula-current);
	--muted-foreground: var(--dracula-comment);
	--accent: var(--dracula-pink);
	--accent-foreground: var(--dracula-bg);
	--destructive: var(--dracula-red);
	--destructive-foreground: var(--dracula-fg);
	--border: var(--dracula-comment);
	--input: var(--dracula-current);
	--ring: var(--dracula-purple);

	/* Chart Colors */
	--chart-1: var(--dracula-purple);
	--chart-2: var(--dracula-cyan);
	--chart-3: var(--dracula-green);
	--chart-4: var(--dracula-orange);
	--chart-5: var(--dracula-pink);

	/* Sidebar */
	--sidebar: var(--dracula-bg);
	--sidebar-foreground: var(--dracula-fg);
	--sidebar-primary: var(--dracula-purple);
	--sidebar-primary-foreground: var(--dracula-bg);
	--sidebar-accent: var(--dracula-current);
	--sidebar-accent-foreground: var(--dracula-fg);
	--sidebar-border: var(--dracula-comment);
	--sidebar-ring: var(--dracula-purple);

	/* Scan Terminal Color Codes */
	--terminal-dns: var(--dracula-cyan);
	--terminal-subdomain: var(--dracula-green);
	--terminal-port: var(--dracula-orange);
	--terminal-error: var(--dracula-red);
	--terminal-info: var(--dracula-comment);
	--terminal-success: var(--dracula-green);
	--terminal-warning: var(--dracula-yellow);
	--terminal-tech: var(--dracula-pink);
}

/* Dark mode is the ONLY mode - no light mode */
.dark {
	/* Already dark by default */
}

@theme inline {
	--animate-scroll: scroll var(--animation-duration, 40s)
		var(--animation-direction, forwards) linear infinite;
	--color-sidebar-ring: var(--sidebar-ring);
	--color-sidebar-border: var(--sidebar-border);
	--color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
	--color-sidebar-accent: var(--sidebar-accent);
	--color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
	--color-sidebar-primary: var(--sidebar-primary);
	--color-sidebar-foreground: var(--sidebar-foreground);
	--color-sidebar: var(--sidebar);
	--color-chart-5: var(--chart-5);
	--color-chart-4: var(--chart-4);
	--color-chart-3: var(--chart-3);
	--color-chart-2: var(--chart-2);
	--color-chart-1: var(--chart-1);
	--color-ring: var(--ring);
	--color-input: var(--input);
	--color-border: var(--border);
	--color-destructive: var(--destructive);
	--color-accent-foreground: var(--accent-foreground);
	--color-accent: var(--accent);
	--color-muted-foreground: var(--muted-foreground);
	--color-muted: var(--muted);
	--color-secondary-foreground: var(--secondary-foreground);
	--color-secondary: var(--secondary);
	--color-primary-foreground: var(--primary-foreground);
	--color-primary: var(--primary);
	--color-popover-foreground: var(--popover-foreground);
	--color-popover: var(--popover);
	--color-card-foreground: var(--card-foreground);
	--color-card: var(--card);
	--color-foreground: var(--foreground);
	--color-background: var(--background);

	@keyframes scroll {
		to {
			transform: translate(calc(-50% - 0.5rem));
		}
	}

	--radius-sm: calc(var(--radius) - 4px);
	--radius-md: calc(var(--radius) - 2px);
	--radius-lg: var(--radius);
	--radius-xl: calc(var(--radius) + 4px);
	--radius-2xl: calc(var(--radius) + 8px);
	--radius-3xl: calc(var(--radius) + 12px);
	--radius-4xl: calc(var(--radius) + 16px);
}

@theme inline {
	--shadow-input:
		0px 2px 3px -1px rgba(0, 0, 0, 0.1),
		0px 1px 0px 0px rgba(25, 28, 33, 0.02),
		0px 0px 0px 1px rgba(25, 28, 33, 0.08);

	--animate-orbit: orbit calc(var(--duration) * 1s) linear infinite;
}

@keyframes orbit {
	0% {
		transform: rotate(calc(var(--angle) * 1deg))
			translateY(calc(var(--radius) * 1px))
			rotate(calc(var(--angle) * -1deg));
	}
	100% {
		transform: rotate(calc(var(--angle) * 1deg + 360deg))
			translateY(calc(var(--radius) * 1px))
			rotate(calc((var(--angle) * -1deg) - 360deg));
	}
}

@theme inline {
	--color-background: var(--background);
	--color-foreground: var(--foreground);
	--font-sans: var(--font-geist-sans);
	--font-mono: var(--font-jetbrains-mono);
}

@layer base {
	* {
		@apply border-border outline-ring/50;
	}
	body {
		@apply bg-background text-foreground;
	}
	html {
		color-scheme: dark;
	}
}

/* Terminal Styles - Chaos-like appearance */
.terminal-output {
	font-family: var(--font-jetbrains-mono), "JetBrains Mono", monospace;
	font-size: 0.875rem;
	line-height: 1.5;
	background: var(--dracula-bg);
	color: var(--dracula-fg);
}

.terminal-line {
	padding: 0.125rem 0;
}

.terminal-line-dns {
	color: var(--terminal-dns);
}

.terminal-line-subdomain {
	color: var(--terminal-subdomain);
}

.terminal-line-port {
	color: var(--terminal-port);
}

.terminal-line-error {
	color: var(--terminal-error);
}

.terminal-line-info {
	color: var(--terminal-info);
}

.terminal-line-success {
	color: var(--terminal-success);
}

.terminal-line-warning {
	color: var(--terminal-warning);
}

.terminal-line-tech {
	color: var(--terminal-tech);
}

/* Scrollbar styling for terminal */
.terminal-output::-webkit-scrollbar {
	width: 8px;
}

.terminal-output::-webkit-scrollbar-track {
	background: var(--dracula-bg);
}

.terminal-output::-webkit-scrollbar-thumb {
	background: var(--dracula-comment);
	border-radius: 4px;
}

.terminal-output::-webkit-scrollbar-thumb:hover {
	background: var(--dracula-purple);
}

::view-transition-old(root),
::view-transition-new(root) {
	animation: none;
	mix-blend-mode: normal;
}

"use client";

import React, { useEffect, useState } from "react";
import {
    motion,
    useAnimationFrame,
    useMotionTemplate,
    useMotionValue,
    useTransform,
} from "motion/react";
import { useRef } from "react";

import { cn } from "@/lib/utils";

export function Button({
    borderRadius = "2rem",
    children,
    as: Component = "button",
    containerClassName,
    borderClassName,
    duration,
    className,
    ...otherProps
}: {
    borderRadius?: string;
    children: React.ReactNode;
    as?: any;
    containerClassName?: string;
    borderClassName?: string;
    duration?: number;
    className?: string;
    [key: string]: any;
}) {
    return (
        <Component
            className={cn(
                "relative h-12 w-50 overflow-hidden bg-transparent p-[1px] text-xl",
                containerClassName
            )}
            style={{
                borderRadius: borderRadius,
            }}
            {...otherProps}
        >
            <div
                className="absolute inset-0"
                style={{ borderRadius: `calc(${borderRadius} * 0.96)` }}
            >
                <MovingBorder duration={duration} rx="30%" ry="30%">
                    <div
                        className={cn(
                            "h-20 w-20 bg-[radial-gradient(#FFD700_40%,transparent_60%)] opacity-[0.8]",
                            borderClassName
                        )}
                    />
                </MovingBorder>
            </div>

            <div
                className={cn(
                    "relative flex h-full w-full items-center justify-center border border-yellow-950 bg-yellow-950/[0.8] text-sm text-white antialiased backdrop-blur-xl",
                    className
                )}
                style={{
                    borderRadius: `calc(${borderRadius} * 0.96)`,
                }}
            >
                {children}
            </div>
        </Component>
    );
}

export const MovingBorder = ({
    children,
    duration = 1500,
    rx,
    ry,
    ...otherProps
}: {
    children: React.ReactNode;
    duration?: number;
    rx?: string;
    ry?: string;
    [key: string]: any;
}) => {
    const pathRef = useRef<SVGPathElement>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const progress = useMotionValue<number>(0);
    const [dimensions, setDimensions] = useState({ width: 160, height: 64 });

    // Get actual container dimensions
    useEffect(() => {
        const updateDimensions = () => {
            if (containerRef.current) {
                const rect = containerRef.current.getBoundingClientRect();
                setDimensions({ width: rect.width, height: rect.height });
            }
        };

        updateDimensions();
        window.addEventListener("resize", updateDimensions);
        return () => window.removeEventListener("resize", updateDimensions);
    }, []);

    useAnimationFrame((time) => {
        const length = pathRef.current?.getTotalLength();
        if (length) {
            const pxPerMillisecond = length / duration;
            progress.set((time * pxPerMillisecond) % length);
        }
    });

    const x = useTransform(progress, (val) => {
        if (pathRef.current) {
            try {
                const point = pathRef.current.getPointAtLength(val);
                return point.x;
            } catch (e) {
                return 0;
            }
        }
        return 0;
    });

    const y = useTransform(progress, (val) => {
        if (pathRef.current) {
            try {
                const point = pathRef.current.getPointAtLength(val);
                return point.y;
            } catch (e) {
                return 0;
            }
        }
        return 0;
    });

    // Calculate rotation angle based on path direction
    const rotation = useTransform(progress, (val) => {
        if (pathRef.current) {
            try {
                const length = pathRef.current.getTotalLength();
                const nextVal = (val + 1) % length;
                const currentPoint = pathRef.current.getPointAtLength(val);
                const nextPoint = pathRef.current.getPointAtLength(nextVal);

                const angle = Math.atan2(
                    nextPoint.y - currentPoint.y,
                    nextPoint.x - currentPoint.x
                );
                return (angle * 180) / Math.PI;
            } catch (e) {
                return 0;
            }
        }
        return 0;
    });

    const transform = useMotionTemplate`translateX(${x}px) translateY(${y}px) translateX(-50%) translateY(-50%) rotate(${rotation}deg)`;

    // Create rounded rectangle path that matches the button border
    const createBorderPath = () => {
        const { width, height } = dimensions;

        // Parse radius values
        const rxPercent = rx ? parseFloat(rx.replace("%", "")) : 25;
        const ryPercent = ry ? parseFloat(ry.replace("%", "")) : 25;

        // Calculate actual radius values
        const cornerRadiusX = Math.min((width * rxPercent) / 100, width / 2);
        const cornerRadiusY = Math.min((height * ryPercent) / 100, height / 2);

        // Create path that traces exactly along the border
        return `
			M ${cornerRadiusX} 0
			L ${width - cornerRadiusX} 0
			Q ${width} 0 ${width} ${cornerRadiusY}
			L ${width} ${height - cornerRadiusY}
			Q ${width} ${height} ${width - cornerRadiusX} ${height}
			L ${cornerRadiusX} ${height}
			Q 0 ${height} 0 ${height - cornerRadiusY}
			L 0 ${cornerRadiusY}
			Q 0 0 ${cornerRadiusX} 0
			Z
		`
            .replace(/\s+/g, " ")
            .trim();
    };

    return (
        <div ref={containerRef} className="absolute inset-0 overflow-visible">
            <svg
                xmlns="http://www.w3.org/2000/svg"
                className="absolute inset-0 pointer-events-none"
                width={dimensions.width}
                height={dimensions.height}
                viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
                {...otherProps}
            >
                <path
                    fill="none"
                    stroke="none"
                    d={createBorderPath()}
                    ref={pathRef}
                />
            </svg>
            <motion.div
                className="absolute pointer-events-none"
                style={{
                    top: 0,
                    left: 0,
                    transform,
                }}
            >
                {children}
            </motion.div>
        </div>
    );
};

