import * as React from "react";
import List from "@mui/material/List";
import ListItem from "@mui/material/ListItem";
import ListItemIcon from "@mui/material/ListItemIcon";
import ListItemText from "@mui/material/ListItemText";
import ListSubheader from "@mui/material/ListSubheader";
import Switch from "@mui/material/Switch";
import Box from "@mui/material/Box";
import { useSnackbar } from "notistack";
import { styled } from "@mui/material/styles";

export function CustomCheckboxList() {
    const [checked, setChecked] = React.useState<string[]>(["quick"]);
    const { enqueueSnackbar } = useSnackbar();

    const handleToggle = (value: string) => () => {
        let newChecked = [...checked];

        if (value === "quick") {
            if (checked.includes("fullscan")) {
                // Replace 'fullscan' with 'quick'
                newChecked = newChecked.filter((item) => item !== "fullscan");
                newChecked.push("quick");
                enqueueSnackbar(
                    "Only one of Quick or Full Scan can be selected.",
                    {
                        variant: "warning",
                    }
                );
            } else if (checked.includes("quick")) {
                // toggle off
                newChecked = newChecked.filter((item) => item !== "quick");
            } else {
                newChecked.push("quick");
            }
        } else if (value === "fullscan") {
            if (checked.includes("quick")) {
                newChecked = newChecked.filter((item) => item !== "quick");
                newChecked.push("fullscan");
                enqueueSnackbar(
                    "Only one of Quick or Full Scan can be selected.",
                    {
                        variant: "warning",
                    }
                );
            } else if (checked.includes("fullscan")) {
                newChecked = newChecked.filter((item) => item !== "fullscan");
            } else {
                newChecked.push("fullscan");
            }
        } else {
            // Normal toggle for other options
            if (checked.includes(value)) {
                newChecked = newChecked.filter((item) => item !== value);
            } else {
                newChecked.push(value);
            }
        }

        setChecked(newChecked);
    };

    return (
        <Box
            sx={{
                width: "100%",
                maxWidth: 360,
                bgcolor: "black",
                color: "white",
            }}
        >
            <List
                subheader={
                    <ListSubheader
                        sx={{
                            bgcolor: "black",
                            color: "white",
                            fontWeight: "bold",
                            fontSize: "22px",
                        }}
                    >
                        Custom Settings
                    </ListSubheader>
                }
            >
                {[
                    { id: "quick", label: "Quick Scan", icon: "quick.svg" },
                    { id: "fullscan", label: "Full Scan", icon: "full.svg" },
                    { id: "ports", label: "Port Scan", icon: "ports.svg" },
                    {
                        id: "subenum",
                        label: "Sub-Domain Enum",
                        icon: "domain.svg",
                    },
                    { id: "dirbf", label: "Dir Brute-Force", icon: "dir.svg" },
                    {
                        id: "cwordlist",
                        label: "Custom Wordlists",
                        icon: "upload.svg",
                    },
                ].map((item) => (
                    <ListItem key={item.id}>
                        <ListItemIcon>
                            <img
                                src={`/${item.icon}`}
                                alt={item.label}
                                width={20}
                                height={20}
                            />
                        </ListItemIcon>
                        <ListItemText
                            id={`switch-list-label-${item.id}`}
                            primary={item.label}
                        />
                        <GoldSwitch
                            edge="end"
                            onChange={handleToggle(item.id)}
                            checked={checked.includes(item.id)}
                            inputProps={{
                                "aria-labelledby": `switch-list-label-${item.id}`,
                            }}
                        />
                    </ListItem>
                ))}
            </List>
        </Box>
    );
}

const GoldSwitch = styled(Switch)(() => ({
    "& .MuiSwitch-switchBase.Mui-checked": {
        color: "#FFD700",
    },
    "& .MuiSwitch-switchBase.Mui-checked + .MuiSwitch-track": {
        backgroundColor: "#FFD700",
    },
}));

"use client";
import { useMotionValue } from "motion/react";
import React, { useState, useEffect } from "react";
import { useMotionTemplate, motion } from "motion/react";
import { cn } from "@/lib/utils";

export const CustomErrorCard = ({
    text,
    className,
}: {
    text?: string;
    className?: string;
}) => {
    let mouseX = useMotionValue(0);
    let mouseY = useMotionValue(0);

    const [randomString, setRandomString] = useState("");

    useEffect(() => {
        let str = generateRandomString(1500);
        setRandomString(str);
    }, []);

    function onMouseMove({ currentTarget, clientX, clientY }: any) {
        let { left, top } = currentTarget.getBoundingClientRect();
        mouseX.set(clientX - left);
        mouseY.set(clientY - top);

        const str = generateRandomString(1500);
        setRandomString(str);
    }

    return (
        <div
            className={cn(
                "p-0.5  bg-transparent aspect-square  flex items-center justify-center w-full h-full relative",
                className
            )}
        >
            <div
                onMouseMove={onMouseMove}
                className="group/card rounded-3xl w-full relative overflow-hidden bg-transparent flex items-center justify-center h-full"
            >
                <CardPattern
                    mouseX={mouseX}
                    mouseY={mouseY}
                    randomString={randomString}
                />
                <div className="relative z-10 flex items-center justify-center">
                    <div className="relative h-44 w-44  rounded-full flex items-center justify-center text-foreground font-bold text-4xl">
                        <div className="absolute w-full h-full bg-card/[0.8] blur-sm rounded-full" />
                        <span className="text-foreground z-20">{text}</span>
                    </div>
                </div>
            </div>
        </div>
    );
};

export function CardPattern({ mouseX, mouseY, randomString }: any) {
    let maskImage = useMotionTemplate`radial-gradient(250px at ${mouseX}px ${mouseY}px, white, transparent)`;
    let style = { maskImage, WebkitMaskImage: maskImage };

    return (
        <div className="pointer-events-none">
            <div className="absolute inset-0 rounded-2xl  [mask-image:linear-gradient(white,transparent)] group-hover/card:opacity-50"></div>
            <motion.div
                className="absolute inset-0 rounded-2xl bg-gradient-to-r from-amber-300 via-yellow-400 to-amber-600 opacity-0 group-hover/card:opacity-100 backdrop-blur-xl transition duration-500"
                style={style}
            />

            <motion.div
                className="absolute inset-0 rounded-2xl opacity-0 mix-blend-overlay  group-hover/card:opacity-100"
                style={style}
            >
                <p className="absolute inset-x-0 text-xs h-full break-words whitespace-pre-wrap text-foreground font-mono font-bold transition duration-500">
                    {randomString}
                </p>
            </motion.div>
        </div>
    );
}

const characters =
    "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
export const generateRandomString = (length: number) => {
    let result = "";
    for (let i = 0; i < length; i++) {
        result += characters.charAt(
            Math.floor(Math.random() * characters.length)
        );
    }
    return result;
};

export const Icon = ({ className, ...rest }: any) => {
    return (
        <svg
            xmlns="http://www.w3.org/2000/svg"
            fill="none"
            viewBox="0 0 24 24"
            strokeWidth="1.5"
            stroke="currentColor"
            className={className}
            {...rest}
        >
            <path
                strokeLinecap="round"
                strokeLinejoin="round"
                d="M12 6v12m6-6H6"
            />
        </svg>
    );
};

"use client";

import React, { useState } from "react";
import {
    motion,
    useTransform,
    AnimatePresence,
    useMotionValue,
    useSpring,
} from "motion/react";

export const AnimatedTooltip = ({
    items,
}: {
    items: {
        id: number;
        name: string;
        designation: string;
        image: string;
    }[];
}) => {
    const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);
    const springConfig = { stiffness: 100, damping: 5 };
    const x = useMotionValue(0); // going to set this value on mouse move
    // rotate the tooltip
    const rotate = useSpring(
        useTransform(x, [-100, 100], [-45, 45]),
        springConfig
    );
    // translate the tooltip
    const translateX = useSpring(
        useTransform(x, [-100, 100], [-50, 50]),
        springConfig
    );
    const handleMouseMove = (event: any) => {
        const halfWidth = event.target.offsetWidth / 2;
        x.set(event.nativeEvent.offsetX - halfWidth); // set the x value, which is then used in transform and rotate
    };

    return (
        <>
            {items.map((item, idx) => (
